    /**
     * Generate a report based on user-selected filters from $_POST
     */
    public function generateReport(array $filters): array
    {
        $sanitizedFilters = $this->sanitizeFilters($filters);
        $reportType = $sanitizedFilters['report_type'] ?? 'orders_summary';

        switch ($reportType) {
            case 'orders_summary':
                return $this->getOrdersSummaryReport($sanitizedFilters);
            case 'revenue_by_category':
                return $this->getRevenueByCategoryReport($sanitizedFilters);
            case 'user_activity':
                return $this->getUserActivityReport($sanitizedFilters);
            case 'orders_detail':
                return $this->getOrdersDetailReport($sanitizedFilters);
            default:
                throw new InvalidArgumentException("Unknown report type: {$reportType}");
        }
    }

    /**
     * Sanitize and validate incoming filter data
     */
    private function sanitizeFilters(array $filters): array
    {
        $sanitized = [];

        // Report type
        $allowedReportTypes = ['orders_summary', 'revenue_by_category', 'user_activity', 'orders_detail'];
        $sanitized['report_type'] = in_array($filters['report_type'] ?? '', $allowedReportTypes, true)
            ? $filters['report_type']
            : 'orders_summary';

        // Date range
        if (!empty($filters['date_from']) && preg_match('/^\d{4}-\d{2}-\d{2}$/', $filters['date_from'])) {
            $sanitized['date_from'] = $filters['date_from'];
        }
        if (!empty($filters['date_to']) && preg_match('/^\d{4}-\d{2}-\d{2}$/', $filters['date_to'])) {
            $sanitized['date_to'] = $filters['date_to'];
        }

        // Status (can be single string or array of statuses)
        if (!empty($filters['status'])) {
            if (is_array($filters['status'])) {
                $sanitized['status'] = array_map('trim', $filters['status']);
                $sanitized['status'] = array_filter($sanitized['status'], fn($s) => $s !== '');
            } else {
                $trimmed = trim($filters['status']);
                if ($trimmed !== '' && $trimmed !== 'all') {
                    $sanitized['status'] = [$trimmed];
                }
            }
        }

        // Category (can be single int or array of ints)
        if (!empty($filters['category'])) {
            if (is_array($filters['category'])) {
                $sanitized['category'] = array_map('intval', $filters['category']);
                $sanitized['category'] = array_filter($sanitized['category'], fn($c) => $c > 0);
            } else {
                $catId = intval($filters['category']);
                if ($catId > 0) {
                    $sanitized['category'] = [$catId];
                }
            }
        }

        // Pagination
        $sanitized['page'] = max(1, intval($filters['page'] ?? 1));
        $sanitized['per_page'] = min(500, max(10, intval($filters['per_page'] ?? 50)));

        // Sort
        $allowedSortFields = ['created_at', 'total_amount', 'status', 'category_name', 'order_count', 'revenue'];
        $sanitized['sort_by'] = in_array($filters['sort_by'] ?? '', $allowedSortFields, true)
            ? $filters['sort_by']
            : 'created_at';

        $sanitized['sort_dir'] = strtoupper($filters['sort_dir'] ?? 'DESC') === 'ASC' ? 'ASC' : 'DESC';

        // Group by period for summary reports
        $allowedGroupBy = ['day', 'week', 'month', 'year'];
        $sanitized['group_by'] = in_array($filters['group_by'] ?? '', $allowedGroupBy, true)
            ? $filters['group_by']
            : 'day';

        // Minimum amount filter
        if (isset($filters['min_amount']) && is_numeric($filters['min_amount'])) {
            $sanitized['min_amount'] = floatval($filters['min_amount']);
        }

        // Maximum amount filter
        if (isset($filters['max_amount']) && is_numeric($filters['max_amount'])) {
            $sanitized['max_amount'] = floatval($filters['max_amount']);
        }

        // Search keyword
        if (!empty($filters['search'])) {
            $sanitized['search'] = trim($filters['search']);
        }

        return $sanitized;
    }

    /**
     * Build WHERE clause and parameters dynamically from filters
     */
    private function buildWhereClause(array $filters, string $dateColumn = 'o.created_at', string $tableAlias = 'o'): array
    {
        $conditions = [];
        $params = [];

        // Date range
        if (!empty($filters['date_from'])) {
            $conditions[] = "{$dateColumn} >= :date_from";
            $params[':date_from'] = $filters['date_from'] . ' 00:00:00';
        }
        if (!empty($filters['date_to'])) {
            $conditions[] = "{$dateColumn} <= :date_to";
            $params[':date_to'] = $filters['date_to'] . ' 23:59:59';
        }

        // Status filter (IN clause with named placeholders)
        if (!empty($filters['status'])) {
            $statusPlaceholders = [];
            foreach ($filters['status'] as $i => $status) {
                $key = ":status_{$i}";
                $statusPlaceholders[] = $key;
                $params[$key] = $status;
            }
            $conditions[] = "{$tableAlias}.status IN (" . implode(', ', $statusPlaceholders) . ")";
        }

        // Category filter (IN clause)
        if (!empty($filters['category'])) {
            $catPlaceholders = [];
            foreach ($filters['category'] as $i => $catId) {
                $key = ":category_{$i}";
                $catPlaceholders[] = $key;
                $params[$key] = $catId;
            }
            $conditions[] = "{$tableAlias}.category_id IN (" . implode(', ', $catPlaceholders) . ")";
        }

        // Amount range
        if (isset($filters['min_amount'])) {
            $conditions[] = "{$tableAlias}.total_amount >= :min_amount";
            $params[':min_amount'] = $filters['min_amount'];
        }
        if (isset($filters['max_amount'])) {
            $conditions[] = "{$tableAlias}.total_amount <= :max_amount";
            $params[':max_amount'] = $filters['max_amount'];
        }

        // Search keyword
        if (!empty($filters['search'])) {
            $conditions[] = "({$tableAlias}.order_number LIKE :search OR u.name LIKE :search_name OR u.email LIKE :search_email)";
            $params[':search'] = '%' . $filters['search'] . '%';
            $params[':search_name'] = '%' . $filters['search'] . '%';
            $params[':search_email'] = '%' . $filters['search'] . '%';
        }

        $whereClause = '';
        if (!empty($conditions)) {
            $whereClause = 'WHERE ' . implode(' AND ', $conditions);
        }

        return ['clause' => $whereClause, 'params' => $params];
    }

    /**
     * Get the date grouping SQL expression
     */
    private function getDateGroupExpression(string $groupBy, string $dateColumn = 'o.created_at'): string
    {
        switch ($groupBy) {
            case 'day':
                return "DATE({$dateColumn})";
            case 'week':
                return "DATE(DATE_SUB({$dateColumn}, INTERVAL WEEKDAY({$dateColumn}) DAY))";
            case 'month':
                return "DATE_FORMAT({$dateColumn}, '%Y-%m')";
            case 'year':
                return "YEAR({$dateColumn})";
            default:
                return "DATE({$dateColumn})";
        }
    }

    /**
     * Orders Summary Report: aggregated by time period
     */
    private function getOrdersSummaryReport(array $filters): array
    {
        $where = $this->buildWhereClause($filters);
        $dateGroupExpr = $this->getDateGroupExpression($filters['group_by']);

        // Main summary query
        $sql = "
            SELECT 
                {$dateGroupExpr} AS period,
                COUNT(*) AS order_count,
                SUM(o.total_amount) AS revenue,
                AVG(o.total_amount) AS avg_order_value,
                COUNT(DISTINCT o.user_id) AS unique_customers,
                SUM(CASE WHEN o.status = 'completed' THEN 1 ELSE 0 END) AS completed_orders,
                SUM(CASE WHEN o.status = 'cancelled' THEN 1 ELSE 0 END) AS cancelled_orders,
                SUM(CASE WHEN o.status = 'pending' THEN 1 ELSE 0 END) AS pending_orders,
                SUM(CASE WHEN o.status = 'refunded' THEN 1 ELSE 0 END) AS refunded_orders
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
            GROUP BY period
            ORDER BY period {$filters['sort_dir']}
        ";

        $stmt = $this->pdo->prepare($sql);
        $stmt->execute($where['params']);
        $rows = $stmt->fetchAll();

        // Totals query
        $totalsSql = "
            SELECT 
                COUNT(*) AS total_orders,
                COALESCE(SUM(o.total_amount), 0) AS total_revenue,
                COALESCE(AVG(o.total_amount), 0) AS overall_avg_order_value,
                COUNT(DISTINCT o.user_id) AS total_unique_customers
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
        ";

        $stmtTotals = $this->pdo->prepare($totalsSql);
        $stmtTotals->execute($where['params']);
        $totals = $stmtTotals->fetch();

        return [
            'report_type' => 'orders_summary',
            'filters_applied' => $filters,
            'totals' => $totals,
            'data' => $rows,
            'row_count' => count($rows),
        ];
    }

