        $mergedParams = array_merge($where['params'], $where['params']);

        // We need to rebuild because named params can't be reused in PDO
        // Rebuild the query with aliased params for the subquery
        $subqueryWhere = $this->buildWhereClauseAliased($filters, 'o2', 'u2', 'sub_');

        $sql = "
            SELECT 
                c.id AS category_id,
