                MAX(o.total_amount) AS max_order_value,
                COUNT(DISTINCT o.user_id) AS unique_customers,
                ROUND(
                    SUM(o.total_amount) / NULLIF((
                        SELECT COALESCE(SUM(o2.total_amount), 1) 
                        FROM orders o2 
                        LEFT JOIN users u2 ON o2.user_id = u2.id
                        LEFT JOIN categories c2 ON o2.category_id = c2.id
                        {$subqueryWhere['clause']}
