    /**
     * Build WHERE clause with aliased parameter names (for subqueries)
     */
    private function buildWhereClauseAliased(array $filters, string $tableAlias = 'o2', string $userAlias = 'u2', string $paramPrefix = 'sub_'): array
    {
        $conditions = [];
        $params = [];
        $dateColumn = "{$tableAlias}.created_at";

        if (!empty($filters['date_from'])) {
            $conditions[] = "{$dateColumn} >= :{$paramPrefix}date_from";
            $params[":{$paramPrefix}date_from"] = $filters['date_from'] . ' 00:00:00';
        }
        if (!empty($filters['date_to'])) {
            $conditions[] = "{$dateColumn} <= :{$paramPrefix}date_to";
            $params[":{$paramPrefix}date_to"] = $filters['date_to'] . ' 23:59:59';
        }

        if (!empty($filters['status'])) {
            $statusPlaceholders = [];
            foreach ($filters['status'] as $i => $status) {
                $key = ":{$paramPrefix}status_{$i}";
                $statusPlaceholders[] = $key;
                $params[$key] = $status;
            }
            $conditions[] = "{$tableAlias}.status IN (" . implode(', ', $statusPlaceholders) . ")";
        }

        if (!empty($filters['category'])) {
            $catPlaceholders = [];
            foreach ($filters['category'] as $i => $catId) {
                $key = ":{$paramPrefix}category_{$i}";
                $catPlaceholders[] = $key;
                $params[$key] = $catId;
            }
            $conditions[] = "{$tableAlias}.category_id IN (" . implode(', ', $catPlaceholders) . ")";
        }

        if (isset($filters['min_amount'])) {
            $conditions[] = "{$tableAlias}.total_amount >= :{$paramPrefix}min_amount";
            $params[":{$paramPrefix}min_amount"] = $filters['min_amount'];
        }
        if (isset($filters['max_amount'])) {
            $conditions[] = "{$tableAlias}.total_amount <= :{$paramPrefix}max_amount";
            $params[":{$paramPrefix}max_amount"] = $filters['max_amount'];
        }

        if (!empty($filters['search'])) {
            $conditions[] = "({$tableAlias}.order_number LIKE :{$paramPrefix}search OR {$userAlias}.name LIKE :{$paramPrefix}search_name OR {$userAlias}.email LIKE :{$paramPrefix}search_email)";
            $params[":{$paramPrefix}search"] = '%' . $filters['search'] . '%';
            $params[":{$paramPrefix}search_name"] = '%' . $filters['search'] . '%';
            $params[":{$paramPrefix}search_email"] = '%' . $filters['search'] . '%';
        }

        $whereClause = '';
        if (!empty($conditions)) {
            $whereClause = 'WHERE ' . implode(' AND ', $conditions);
        }

        return ['clause' => $whereClause, 'params' => $params];
    }

    /**
     * User Activity Report
     */
    private function getUserActivityReport(array $filters): array
    {
        $where = $this->buildWhereClause($filters);
        $offset = ($filters['page'] - 1) * $filters['per_page'];

        // Count total
        $countSql = "
            SELECT COUNT(DISTINCT o.user_id) AS total
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
        ";

        $stmtCount = $this->pdo->prepare($countSql);
        $stmtCount->execute($where['params']);
        $totalUsers = (int) $stmtCount->fetchColumn();

        $sortBy = in_array($filters['sort_by'], ['revenue', 'order_count', 'created_at'])
            ? $filters['sort_by']
            : 'revenue';

        // Main data
        $sql = "
            SELECT 
                u.id AS user_id,
                u.name AS user_name,
                u.email AS user_email,
                COUNT(*) AS order_count,
                SUM(o.total_amount) AS total_spent,
                AVG(o.total_amount) AS avg_order_value,
                MIN(o.created_at) AS first_order_date,
                MAX(o.created_at) AS last_order_date,
                DATEDIFF(MAX(o.created_at), MIN(o.created_at)) AS customer_lifetime_days,
                GROUP_CONCAT(DISTINCT o.status ORDER BY o.status) AS order_statuses
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
            GROUP BY u.id, u.name, u.email
            ORDER BY {$sortBy} {$filters['sort_dir']}
            LIMIT :limit OFFSET :offset
        ";

        $stmt = $this->pdo->prepare($sql);
        foreach ($where['params'] as $key => $value) {
            $stmt->bindValue($key, $value);
        }
        $stmt->bindValue(':limit', $filters['per_page'], PDO::PARAM_INT);
        $stmt->bindValue(':offset', $offset, PDO::PARAM_INT);
        $stmt->execute();
        $rows = $stmt->fetchAll();

        $totalPages = (int) ceil($totalUsers / $filters['per_page']);

        return [
            'report_type' => 'user_activity',
            'filters_applied' => $filters,
            'pagination' => [
                'current_page' => $filters['page'],
                'per_page' => $filters['per_page'],
                'total_records' => $totalUsers,
                'total_pages' => $totalPages,
            ],
            'data' => $rows,
            'row_count' => count($rows),
        ];
    }

    /**
     * Detailed Orders Report with full order information
     */
    private function getOrdersDetailReport(array $filters): array
    {
        $where = $this->buildWhereClause($filters);
        $offset = ($filters['page'] - 1) * $filters['per_page'];

        // Count total matching orders
        $countSql = "
            SELECT COUNT(*) AS total
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
        ";

        $stmtCount = $this->pdo->prepare($countSql);
        $stmtCount->execute($where['params']);
        $totalOrders = (int) $stmtCount->fetchColumn();

        $allowedSorts = ['created_at', 'total_amount', 'status'];
        $sortBy = in_array($filters['sort_by'], $allowedSorts) ? "o.{$filters['sort_by']}" : 'o.created_at';

        // Main detail query
        $sql = "
            SELECT 
                o.id AS order_id,
                o.order_number,
                o.status,
                o.total_amount,
                o.created_at,
                o.updated_at,
                u.id AS user_id,
                u.name AS user_name,
                u.email AS user_email,
                c.id AS category_id,
                c.name AS category_name
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
            ORDER BY {$sortBy} {$filters['sort_dir']}
            LIMIT :limit OFFSET :offset
        ";

        $stmt = $this->pdo->prepare($sql);
        foreach ($where['params'] as $key => $value) {
            $stmt->bindValue($key, $value);
        }
        $stmt->bindValue(':limit', $filters['per_page'], PDO::PARAM_INT);
        $stmt->bindValue(':offset', $offset, PDO::PARAM_INT);
        $stmt->execute();
        $rows = $stmt->fetchAll();

        // Summary stats for the filtered set
        $statsSql = "
            SELECT 
                COALESCE(SUM(o.total_amount), 0) AS total_revenue,
                COALESCE(AVG(o.total_amount), 0) AS avg_order_value,
                COALESCE(MIN(o.total_amount), 0) AS min_order_value,
                COALESCE(MAX(o.total_amount), 0) AS max_order_value
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
        ";

        $stmtStats = $this->pdo->prepare($statsSql);
        $stmtStats->execute($where['params']);
        $stats = $stmtStats->fetch();

        $totalPages = (int) ceil($totalOrders / $filters['per_page']);

        return [
            'report_type' => 'orders_detail',
            'filters_applied' => $filters,
            'summary_stats' => $stats,
            'pagination' => [
                'current_page' => $filters['page'],
                'per_page' => $filters['per_page'],
                'total_records' => $totalOrders,
                'total_pages' => $totalPages,
            ],
            'data' => $rows,
            'row_count' => count($rows),
        ];
    }

    /**
     * Export report data as CSV
     */
    public function exportReportAsCsv(array $reportData): void
    {
        $filename = $reportData['report_type'] . '_' . date('Y-m-d_His') . '.csv';

        header('Content-Type: text/csv; charset=utf-8');
        header("Content-Disposition: attachment; filename=\"{$filename}\"");

        $output = fopen('php://output', 'w');

        if (!empty($reportData['data'])) {
            // Header row
            fputcsv($output, array_keys($reportData['data'][0]));

            // Data rows
            foreach ($reportData['data'] as $row) {
                fputcsv($output, $row);
            }
        }

        fclose($output);
    }

    /**
     * Get dashboard overview/KPI widgets data
     */
    public function getDashboardOverview(array $filters): array
    {
        $where = $this->buildWhereClause($filters);

        // Today's stats
        $todaySql = "
            SELECT 
                COUNT(*) AS orders_today,
                COALESCE(SUM(total_amount), 0) AS revenue_today
            FROM orders
            WHERE DATE(created_at) = CURDATE()
        ";
        $todayStats = $this->pdo->query($todaySql)->fetch();

        // Filtered period stats
        $periodSql = "
            SELECT 
                COUNT(*) AS total_orders,
                COALESCE(SUM(o.total_amount), 0) AS total_revenue,
                COALESCE(AVG(o.total_amount), 0) AS avg_order_value,
                COUNT(DISTINCT o.user_id) AS unique_customers,
                SUM(CASE WHEN o.status = 'completed' THEN 1 ELSE 0 END) AS completed_orders,
                SUM(CASE WHEN o.status = 'pending' THEN 1 ELSE 0 END) AS pending_orders,
                SUM(CASE WHEN o.status = 'cancelled' THEN 1 ELSE 0 END) AS cancelled_orders,
                SUM(CASE WHEN o.status = 'refunded' THEN o.total_amount ELSE 0 END) AS refunded_amount
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
        ";

        $stmtPeriod = $this->pdo->prepare($periodSql);
        $stmtPeriod->execute($where['params']);
        $periodStats = $stmtPeriod->fetch();

        // Top 5 categories by revenue in period
        $topCatSql = "
            SELECT 
                c.name AS category_name,
                SUM(o.total_amount) AS revenue,
                COUNT(*) AS order_count
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
            GROUP BY c.id, c.name
            ORDER BY revenue DESC
            LIMIT 5
        ";

        $stmtTopCat = $this->pdo->prepare($topCatSql);
        $stmtTopCat->execute($where['params']);
        $topCategories = $stmtTopCat->fetchAll();

        // Top 5 customers by spend in period
        $topCustSql = "
            SELECT 
                u.name AS customer_name,
                u.email AS customer_email,
                SUM(o.total_amount) AS total_spent,
                COUNT(*) AS order_count
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            LEFT JOIN categories c ON o.category_id = c.id
            {$where['clause']}
            GROUP BY u.id, u.name, u.email
            ORDER BY total_spent DESC
            LIMIT 5
        ";

        $stmtTopCust = $this->pdo->prepare($topCustSql);
        $stmtTopCust->execute($where['params']);
        $topCustomers = $stmtTopCust->fetchAll();

        return [
            'today' => $todayStats,
            'period' => $periodStats,
            'top_categories' => $topCategories,
            'top_customers' => $topCustomers,
        ];
    }
