        $filters = $_POST;

        // Determine action
        $action = $_POST['action'] ?? 'overview';

        switch ($action) {
            case 'overview':
                $result = $dashboard->getDashboardOverview($filters);
                break;

            case 'generate_report':
                $result = $dashboard->generateReport($filters);
                break;

            case 'export_csv':
                $reportData = $dashboard->generateReport($filters);
                $dashboard->exportReportAsCsv($reportData);
                return;

            case 'get_filters':
                $result = $dashboard->getFilterOptions();
                break;

            default:
                $result = ['error' => 'Unknown action'];
        }

        header('Content-Type: application/json');
        echo json_encode($result, JSON_PRETTY_PRINT);

    } catch (PDOException $e) {
        http_response_code(500);
        header('Content-Type: application/json');
        echo json_encode([
            'error' => 'Database error',
            'message' => $e->getMessage(),
        ]);
    } catch (InvalidArgumentException $e) {
        http_response_code(400);
        header('Content-Type: application/json');
        echo json_encode([
            'error' => 'Invalid request',
            'message' => $e->getMessage(),
        ]);
    }
}

